def is_prime(n):
    """判断一个数是否为质数"""
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    # 只需检查到该数平方根的奇数即可
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False

    return True
